import{_ as a,o as i,c as s,ak as n}from"./chunks/framework.BZTYhN8l.js";const g=JSON.parse('{"title":"MinIO 中 Key 的缓存设计问题","description":"","frontmatter":{},"headers":[],"relativePath":"Java 文档/Minio 中 Key 的缓存问题.md","filePath":"Java 文档/Minio 中 Key 的缓存问题.md","lastUpdated":1775065365000}'),l={name:"Java 文档/Minio 中 Key 的缓存问题.md"};function t(r,e,h,p,d,o){return i(),s("div",null,[...e[0]||(e[0]=[n(`<p>我帮你按<strong>技术文档 + 架构说明</strong>的风格做了一版润色，逻辑更严谨、表达更工程化，也更适合放到项目文档或面试说明中👇</p><hr><h1 id="minio-中-key-的缓存设计问题" tabindex="-1">MinIO 中 Key 的缓存设计问题 <a class="header-anchor" href="#minio-中-key-的缓存设计问题" aria-label="Permalink to “MinIO 中 Key 的缓存设计问题”">​</a></h1><h2 id="一、minio-的缓存定位" tabindex="-1">一、MinIO 的缓存定位 <a class="header-anchor" href="#一、minio-的缓存定位" aria-label="Permalink to “一、MinIO 的缓存定位”">​</a></h2><p>在系统架构中，MinIO 属于<strong>基础设施层服务（Infrastructure Service）</strong>，主要负责对象存储能力，对上层业务模块（如 user、order、content 等）提供统一访问接口。</p><p>因此：</p><blockquote><p><strong>MinIO 相关缓存属于“资源级缓存”，而非“业务级缓存”</strong></p></blockquote><hr><h2 id="二、使用统一缓存-key-的必要性" tabindex="-1">二、使用统一缓存 Key 的必要性 <a class="header-anchor" href="#二、使用统一缓存-key-的必要性" aria-label="Permalink to “二、使用统一缓存 Key 的必要性”">​</a></h2><h3 id="❌-错误做法-使用业务化-rediskeybuilder" tabindex="-1">❌ 错误做法：使用业务化 RedisKeyBuilder <a class="header-anchor" href="#❌-错误做法-使用业务化-rediskeybuilder" aria-label="Permalink to “❌ 错误做法：使用业务化 RedisKeyBuilder”">​</a></h3><p>如果使用类似 RedisKeyBuilder 的方式构建 Key：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user:minio:a.png</span></span>
<span class="line"><span>order:minio:a.png</span></span></code></pre></div><p>会导致以下问题：</p><h3 id="_1️⃣-重复缓存-数据冗余" tabindex="-1">1️⃣ 重复缓存（数据冗余） <a class="header-anchor" href="#_1️⃣-重复缓存-数据冗余" aria-label="Permalink to “1️⃣ 重复缓存（数据冗余）”">​</a></h3><p>同一资源 <code>a.png</code> 被存储多份：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user:minio:a.png</span></span>
<span class="line"><span>order:minio:a.png</span></span></code></pre></div><p>Redis 无法感知它们是同一资源。</p><hr><h3 id="_2️⃣-重复-rpc-调用" tabindex="-1">2️⃣ 重复 RPC 调用 <a class="header-anchor" href="#_2️⃣-重复-rpc-调用" aria-label="Permalink to “2️⃣ 重复 RPC 调用”">​</a></h3><p>不同模块访问时：</p><ul><li>user 模块缓存 miss → 调用 MinIO → 写入缓存</li><li>order 模块缓存 miss → 再次调用 MinIO → 再写入缓存</li></ul><p>👉 导致<strong>不必要的远程调用开销</strong></p><hr><h3 id="_3️⃣-缓存命中率下降" tabindex="-1">3️⃣ 缓存命中率下降 <a class="header-anchor" href="#_3️⃣-缓存命中率下降" aria-label="Permalink to “3️⃣ 缓存命中率下降”">​</a></h3><p>由于 Key 不统一：</p><p>👉 各模块缓存相互隔离，无法复用</p><hr><h2 id="✅-正确做法-去业务化-key-设计" tabindex="-1">✅ 正确做法：去业务化 Key 设计 <a class="header-anchor" href="#✅-正确做法-去业务化-key-设计" aria-label="Permalink to “✅ 正确做法：去业务化 Key 设计”">​</a></h2><p>应统一使用资源级 Key，例如：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>minio:presigned:a.png</span></span></code></pre></div><p>特点：</p><ul><li>与业务模块解耦</li><li>全局唯一</li><li>多模块共享缓存</li></ul><p>👉 从而实现：</p><ul><li>减少重复调用</li><li>提高缓存命中率</li><li>降低 Redis 存储成本</li></ul><hr><h2 id="三、expiresecond-对缓存设计的影响" tabindex="-1">三、expireSecond 对缓存设计的影响 <a class="header-anchor" href="#三、expiresecond-对缓存设计的影响" aria-label="Permalink to “三、expireSecond 对缓存设计的影响”">​</a></h2><p>MinIO 预签名 URL 与过期时间强相关：</p><blockquote><p><strong>不同 expireSecond 会生成不同的 URL</strong></p></blockquote><hr><h3 id="❌-情况一-key-不包含-expiresecond" tabindex="-1">❌ 情况一：Key 不包含 expireSecond <a class="header-anchor" href="#❌-情况一-key-不包含-expiresecond" aria-label="Permalink to “❌ 情况一：Key 不包含 expireSecond”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>key = minio:presigned:a.png</span></span></code></pre></div><h4 id="问题" tabindex="-1">问题： <a class="header-anchor" href="#问题" aria-label="Permalink to “问题：”">​</a></h4><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一次请求：expire = 60 → 缓存 URL_A（1分钟）</span></span>
<span class="line"><span>第二次请求：expire = 300 → 命中缓存 → 返回 URL_A ❌</span></span></code></pre></div><p>👉 导致：</p><ul><li>返回的 URL 过期时间错误</li><li>破坏接口语义一致性</li></ul><hr><h3 id="✅-情况二-key-包含-expiresecond-推荐" tabindex="-1">✅ 情况二：Key 包含 expireSecond（推荐） <a class="header-anchor" href="#✅-情况二-key-包含-expiresecond-推荐" aria-label="Permalink to “✅ 情况二：Key 包含 expireSecond（推荐）”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>key = minio:presigned:a.png:60</span></span>
<span class="line"><span>key = minio:presigned:a.png:300</span></span></code></pre></div><h4 id="优点" tabindex="-1">优点： <a class="header-anchor" href="#优点" aria-label="Permalink to “优点：”">​</a></h4><ul><li>不同过期时间 → 对应不同缓存</li><li>保证 URL 语义正确</li><li>避免错误复用</li></ul><hr><h3 id="⚠️-引入的新问题-key-膨胀" tabindex="-1">⚠️ 引入的新问题：Key 膨胀 <a class="header-anchor" href="#⚠️-引入的新问题-key-膨胀" aria-label="Permalink to “⚠️ 引入的新问题：Key 膨胀”">​</a></h3><p>如果 expireSecond 取值不受控：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>a.png:60</span></span>
<span class="line"><span>a.png:61</span></span>
<span class="line"><span>a.png:62</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>👉 会导致：</p><ul><li>Key 数量爆炸</li><li>Redis 内存压力增大</li><li>缓存命中率下降</li></ul><hr><h2 id="四、优化策略-关键" tabindex="-1">四、优化策略（关键） <a class="header-anchor" href="#四、优化策略-关键" aria-label="Permalink to “四、优化策略（关键）”">​</a></h2><h3 id="✅-方案一-规范-expiresecond-推荐" tabindex="-1">✅ 方案一：规范 expireSecond（推荐） <a class="header-anchor" href="#✅-方案一-规范-expiresecond-推荐" aria-label="Permalink to “✅ 方案一：规范 expireSecond（推荐）”">​</a></h3><p>限制为固定值集合：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>60 / 300 / 600</span></span></code></pre></div><p>👉 优点：</p><ul><li>控制 Key 数量</li><li>提高复用率</li><li>易于维护</li></ul><hr><h3 id="✅-方案二-统一过期时间" tabindex="-1">✅ 方案二：统一过期时间 <a class="header-anchor" href="#✅-方案二-统一过期时间" aria-label="Permalink to “✅ 方案二：统一过期时间”">​</a></h3><p>系统内部约定：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>统一使用 300 秒</span></span></code></pre></div><p>👉 适用于对时效要求不敏感的场景</p><hr><h3 id="✅-方案三-合理设置-redis-ttl" tabindex="-1">✅ 方案三：合理设置 Redis TTL <a class="header-anchor" href="#✅-方案三-合理设置-redis-ttl" aria-label="Permalink to “✅ 方案三：合理设置 Redis TTL”">​</a></h3><p>Redis Key 的过期时间建议：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TTL &lt;= expireSecond</span></span></code></pre></div><p>避免缓存返回“即将过期”的 URL。</p><hr><h2 id="五、总结" tabindex="-1">五、总结 <a class="header-anchor" href="#五、总结" aria-label="Permalink to “五、总结”">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to “核心原则”">​</a></h3><ol><li><strong>MinIO 缓存是资源级缓存，必须去业务化</strong></li><li><strong>缓存 Key 应只与 objectName（及必要参数）相关</strong></li><li><strong>expireSecond 决定 URL 版本，必须纳入 Key 设计</strong></li></ol><hr><h3 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h3><blockquote><p><strong>同一 objectName 必须共享缓存，不同 expireSecond 必须区分缓存，同时通过规范参数避免 Key 膨胀</strong></p></blockquote><hr><p>如果你后面要写到项目亮点或面试，我可以帮你再压缩成一段<strong>“面试标准答案版”</strong>，会更有杀伤力。</p>`,82)])])}const k=a(l,[["render",t]]);export{g as __pageData,k as default};
